INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES (1, "", 3, 10, 1, "怖い魔物もたくさんいますけど\n探せばぴにゃこら太さんや\nプチグリフォンさんみたいに\nかわいい魔物もいると思うんですよね！", 112411, "", 11, 1030016, "");
INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES ("", "", 3, "", "", "", 0, "", 91, 1030017, "");
