INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES (1, "", 3, 10, 1, "かわいいですよ～\n私たちの歌で、たくさんの\nぴにゃこら太さんを\n集められませんかね？", 112411, "", 11, 1030028, "");
INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES ("", "", 3, "", "", "", 0, "", 91, 1030029, "");
