INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES (1, "", 3, 10, 1, "あっ、たしかにそうですね！\nまずは目の前のぴにゃこら太さんに\n認めてもらわなきゃですし♪", 112411, "", 11, 1030038, "");
