INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES (1, "", 6, 10, 1, "あの人にとっては何気ない\n一言だったのかも知れないですけど\n私にはそれがとてもうれしくて", 112411, "", 11, 1060026, "");
INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES ("", "", 6, "", "", "", 0, "", 91, 1060027, "");
