INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES ("", "", 7, 0, 0, "vo_omp_7007_004", "vo_omp_7007", "", 21, 1070035, "");
INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES (1, "", 7, 10, 1, "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", 112611, "", 11, 1070036, "");
INSERT INTO `v1_8bc415d7a6ffad63d61d68a9ffe76b339477b4a28551eaa890e802861136a588` VALUES ("", "", 7, "", "", "", 0, "", 91, 1070037, "");
